     1→import { api } from "./api.js";
     2→
     3→// ── Helpers ─────────────────────────────────────────────
     4→function showError(el, msg) {
     5→    el.innerHTML = `<div class="alert alert-error">${msg}</div>`;
     6→}
     7→function showSuccess(el, msg) {
     8→    el.innerHTML = `<div class="alert alert-success">${msg}</div>`;
     9→    setTimeout(() => { el.innerHTML = ""; }, 3000);
    10→}
    11→
    12→// ── Tabs ─────────────────────────────────────────────────
    13→document.querySelectorAll(".tab-btn").forEach(btn => {
    14→    btn.addEventListener("click", () => {
    15→        document.querySelectorAll(".tab-btn").forEach(b => b.classList.remove("active"));
    16→        document.querySelectorAll(".tab-panel").forEach(p => p.classList.remove("active"));
    17→        btn.classList.add("active");
    18→        document.getElementById(btn.dataset.tab).classList.add("active");
    19→    });
    20→});
    21→
    22→// ════════════════════════════════════════════════════════
    23→// Plans tab
    24→// ════════════════════════════════════════════════════════
    25→const plansList     = document.getElementById("plans-list");
    26→const planFormError = document.getElementById("plan-form-error");
    27→const planFormMsg   = document.getElementById("plan-form-msg");
    28→const createPlanBtn = document.getElementById("create-plan-btn");
    29→
    30→async function loadPlans() {
    31→    plansList.innerHTML = `<div class="skeleton" style="height:80px"></div>`;
    32→    try {
    33→        const plans = await api.listPlans();
    34→        renderPlansList(plans);
    35→    } catch (err) {
    36→        showError(plansList, err.message);
    37→    }
    38→}
    39→
    40→function renderPlansList(plans) {
    41→    if (plans.length === 0) {
    42→        plansList.innerHTML = `<div class="empty-state">No plans yet.</div>`;
    43→        return;
    44→    }
    45→    plansList.innerHTML = plans.map(p => renderPlanCard(p)).join("");
    46→    // Wire rule forms
    47→    plans.forEach(p => wirePlanCard(p));
    48→}
    49→
    50→function renderPlanCard(plan) {
    51→    const rules = plan.coverage_rules;
    52→    return `
    53→        <div class="card" style="margin-bottom:12px" id="plan-card-${plan.id}">
    54→            <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;flex-wrap:wrap;gap:8px">
    55→                <div>
    56→                    <strong>${plan.name}</strong>
    57→                    <span class="id-mono" style="margin-left:8px">${plan.id.slice(0, 8)}…</span>
    58→                </div>
    59→                <div style="color:var(--text-muted);font-size:13px">Deductible: <strong>$${parseFloat(plan.deductible).toFixed(2)}</strong></div>
    60→            </div>
    61→
    62→            <!-- Coverage rules table -->
    63→            <div class="table-wrap" style="margin-bottom:12px">
    64→                <table>
    65→                    <thead>
    66→                        <tr>
    67→                            <th>CPT Code</th>
    68→                            <th>Covered</th>
    69→                            <th>Coverage %</th>
    70→                            <th></th>
    71→                        </tr>
    72→                    </thead>
    73→                    <tbody id="rules-body-${plan.id}">
    74→                        ${rules.length === 0
    75→                            ? `<tr><td colspan="4"><em style="color:var(--text-muted)">No rules yet.</em></td></tr>`
    76→                            : rules.map(r => renderRuleRow(plan.id, r)).join("")}
    77→                    </tbody>
    78→                </table>
    79→            </div>
    80→
    81→            <!-- Add/edit rule form -->
    82→            <details>
    83→                <summary style="cursor:pointer;font-size:13px;color:var(--primary);margin-bottom:10px">+ Add / Edit Coverage Rule</summary>
    84→                <div class="form-row-3" style="margin-top:10px">
    85→                    <div class="form-group">
    86→                        <label>CPT Code</label>
    87→                        <input id="rule-cpt-${plan.id}" class="form-control" placeholder="e.g. 99213">
    88→                    </div>
    89→                    <div class="form-group">
    90→                        <label>Covered?</label>
    91→                        <select id="rule-covered-${plan.id}" class="form-control">
    92→                            <option value="true">Yes</option>
    93→                            <option value="false">No</option>
    94→                        </select>
    95→                    </div>
    96→                    <div class="form-group">
    97→                        <label>Coverage % (0–1)</label>
    98→                        <input id="rule-pct-${plan.id}" class="form-control" type="number" min="0" max="1" step="0.01" placeholder="e.g. 0.8">
    99→                    </div>
   100→                </div>
   101→                <div id="rule-error-${plan.id}"></div>
   102→                <button class="btn btn-primary btn-sm upsert-rule-btn" data-plan="${plan.id}">Save Rule</button>
   103→            </details>
   104→        </div>`;
   105→}
   106→
   107→function renderRuleRow(planId, rule) {
   108→    return `
   109→        <tr>
   110→            <td class="text-mono">${rule.cpt_code}</td>
   111→            <td>${rule.is_covered ? "✓ Yes" : "✗ No"}</td>
   112→            <td>${(parseFloat(rule.coverage_percentage) * 100).toFixed(0)}%</td>
   113→            <td>
   114→                <button class="btn btn-outline btn-sm delete-rule-btn"
   115→                    data-plan="${planId}" data-cpt="${rule.cpt_code}">Delete</button>
   116→            </td>
   117→        </tr>`;
   118→}
   119→
   120→function wirePlanCard(plan) {
   121→    // Upsert rule
   122→    const card = document.getElementById(`plan-card-${plan.id}`);
   123→    if (!card) return;
   124→
   125→    card.querySelectorAll(".upsert-rule-btn").forEach(btn => {
   126→        btn.addEventListener("click", async () => {
   127→            const pid     = btn.dataset.plan;
   128→            const cpt     = document.getElementById(`rule-cpt-${pid}`).value.trim();
   129→            const covered = document.getElementById(`rule-covered-${pid}`).value === "true";
   130→            const pct     = document.getElementById(`rule-pct-${pid}`).value;
   131→            const errEl   = document.getElementById(`rule-error-${pid}`);
   132→
   133→            if (!cpt || !pct) { showError(errEl, "CPT code and coverage % are required."); return; }
   134→
   135→            btn.disabled = true;
   136→            try {
   137→                await api.upsertCoverageRule(pid, cpt, { is_covered: covered, coverage_percentage: parseFloat(pct) });
   138→                await loadPlans();
   139→            } catch (err) {
   140→                showError(errEl, err.message);
   141→                btn.disabled = false;
   142→            }
   143→        });
   144→    });
   145→
   146→    // Delete rule
   147→    card.querySelectorAll(".delete-rule-btn").forEach(btn => {
   148→        btn.addEventListener("click", async () => {
   149→            if (!confirm(`Delete coverage rule for CPT ${btn.dataset.cpt}?`)) return;
   150→            btn.disabled = true;
   151→            try {
   152→                await api.deleteCoverageRule(btn.dataset.plan, btn.dataset.cpt);
   153→                await loadPlans();
   154→            } catch (err) {
   155→                alert(err.message);
   156→                btn.disabled = false;
   157→            }
   158→        });
   159→    });
   160→}
   161→
   162→createPlanBtn.addEventListener("click", async () => {
   163→    const name        = document.getElementById("plan-name").value.trim();
   164→    const deductible  = document.getElementById("plan-deductible").value;
   165→    planFormError.innerHTML = "";
   166→
   167→    if (!name || !deductible) { showError(planFormError, "Name and deductible are required."); return; }
   168→
   169→    createPlanBtn.disabled = true;
   170→    createPlanBtn.textContent = "Creating…";
   171→    try {
   172→        await api.createPlan({ name, deductible: parseFloat(deductible) });
   173→        showSuccess(planFormMsg, `Plan "${name}" created.`);
   174→        document.getElementById("plan-name").value = "";
   175→        document.getElementById("plan-deductible").value = "";
   176→        await loadPlans();
   177→    } catch (err) {
   178→        showError(planFormError, err.message);
   179→    } finally {
   180→        createPlanBtn.disabled = false;
   181→        createPlanBtn.textContent = "Create Plan";
   182→    }
   183→});
   184→
   185→// ════════════════════════════════════════════════════════
   186→// Providers tab
   187→// ════════════════════════════════════════════════════════
   188→const providersList     = document.getElementById("providers-list");
   189→const providerFormError = document.getElementById("provider-form-error");
   190→const providerFormMsg   = document.getElementById("provider-form-msg");
   191→const createProviderBtn = document.getElementById("create-provider-btn");
   192→
   193→async function loadProviders() {
   194→    providersList.innerHTML = `<div class="skeleton" style="height:60px"></div>`;
   195→    try {
   196→        const providers = await api.listProviders();
   197→        if (providers.length === 0) {
